from typing import Callable


class FilteredMessageBus(MessageBus):
    """Extends MessageBus with optional per-subscription predicates."""

    def __init__(self):
        super().__init__()
        # queue -> predicate function
        self._predicates: dict[int, Callable[[EventMessage], bool]] = {}

    def subscribe(
        self,
        topic: str,
        predicate: Callable[[EventMessage], bool] | None = None,
    ) -> asyncio.Queue:
        q = super().subscribe(topic)
        if predicate:
            self._predicates[id(q)] = predicate
        return q

    def publish(self, event: EventMessage) -> int:
        delivered = 0
        for topic_key in (event.topic, "__all__"):
            for q in self._subscribers.get(topic_key, []):
                pred = self._predicates.get(id(q))
                if pred is None or pred(event):
                    q.put_nowait(deepcopy(event))
                    delivered += 1
        return delivered


# Example: alerting agent only cares about high-severity alerts
filtered_bus = FilteredMessageBus()
high_severity_q = filtered_bus.subscribe(
    "alerts",
    predicate=lambda ev: ev.payload.get("severity", 0) >= 8,
)
